#include <bits/stdc++.h>
using namespace std;

const int N=1e4+10,M=5e4+10;

int n,m;
int head[N],ver[M],nxt[M],tot;
int dfn[N],low[N],num,stk[N],top,cnt,ans;
bool ins[N];

void add(int u,int v){
    ver[++tot]=v,nxt[tot]=head[u],head[u]=tot;
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    stk[++top]=x,ins[x]=1;
    for(int i=head[x],y;i;i=nxt[i])
        if(!dfn[y=ver[i]]){
            tarjan(y);
            low[x]=min(low[x],low[y]);
        }else if(ins[y])
            low[x]=min(low[x],dfn[y]);
    if(dfn[x]==low[x]){
        int z,sum=0;
        cnt++;
        do{
            z=stk[top--],ins[z]=0,sum++;
        }while(z!=x);
        ans+=(sum>1);
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        add(u,v);
    }
    for(int i=1;i<=n;i++)
        if(!dfn[i])
            tarjan(i);
    printf("%d",ans);
    return 0;
}
